import * as React from "react";
import styled from "styled-components";

// images as components
import Logo from "../images/logo.svg";
import LogoDark from "../images/logo_dark.svg";
import { media } from "./media-queries";

export const MainHeader = ({ dark = false }) => {
  return (
    <Header>
      <a href="/">{dark ? <LogoDark /> : <Logo />}</a>
      <div className="links">
        <HeaderLink href="/#whatwedo" className="mobile-hidden" $dark={dark}>
          What we do
        </HeaderLink>
        <HeaderLink href="/#howitworks" className="mobile-hidden" $dark={dark}>
          How it works
        </HeaderLink>
        <HeaderLink href="/#whoweare" className="mobile-hidden" $dark={dark}>
          Who we are
        </HeaderLink>
        <HeaderLink href="/contact" $dark={dark}>
          Contact
        </HeaderLink>
      </div>
    </Header>
  );
};

const Header = styled.header`
  z-index: 1;
  padding: 24px;
  display: flex;
  justify-content: space-between;
  position: absolute;
  top: 0;
  right: 0;
  left: 0;

  ${media.m`
    padding: 24px 39px;
  `}

  ${media.l`
    padding: 24px 40px;
  `}

  ${media.xl`
    padding: 24px 68px;
  `}
`;

const HeaderLink = styled.a`
  font-family: "Poppins";
  font-style: normal;
  font-weight: 500;
  font-size: 14px;
  line-height: 21px;

  letter-spacing: 0.03em;

  ${({ $dark }) => {
    return $dark ? `color: #47474F;` : `color: #ffffff;`;
  }}

  text-decoration: none;

  transition-property: color;
  transition-duration: 0.3s;
  &:hover {
    ${({ $dark }) => {
      return $dark
        ? `color: rgb(71 71 79 / 75%);`
        : `color: rgb(255 255 255 / 75%);`;
    }}
  }

  &:not(:last-child)::after {
    content: "/";
    ${({ $dark }) => {
      return $dark ? `color: #47474F;` : `color: #ffffff;`;
    }}
    display: inline-block;
    vertical-align: middle;
    opacity: 0.3;
    font-family: "Montserrat";
    line-height: 22px;
    padding: 0 16px;
    font-size: 18px;
    ${media.l`
      font-size: 24px;
      padding: 0 24px;
    `}

    &:hover {
      opacity: 1;
    }
  }

  ${media.m`
    font-size: 13px;
  `}

  ${media.l`
    font-size: 15px;
  `}

  ${media.xl`
    font-size: 18px;
  `}
`;
